import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { Plus, Trash2, X, Package, Edit2 } from 'lucide-react';
import API from '../../utils/api';
import AdminLayout from './AdminLayout';
import toast from 'react-hot-toast';

const CATEGORIES = ['protein','creatine','pre-workout','vitamins','weight-gainer','fat-burner','bcaa','accessories','apparel','other'];

const emptyForm = { name: '', description: '', category: 'protein', brand: '', price: '', discountPrice: '', stock: '', flavors: '', weights: '', isFeatured: false };

export default function AdminStore() {
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [modal, setModal] = useState(false);
  const [form, setForm] = useState(emptyForm);
  const [editId, setEditId] = useState(null);
  const [imageFiles, setImageFiles] = useState([]);
  const [saving, setSaving] = useState(false);

  const load = () => API.get('/store').then(r => setProducts(r.data)).catch(() => {}).finally(() => setLoading(false));
  useEffect(load, []);

  const handleChange = e => setForm({ ...form, [e.target.name]: e.target.type === 'checkbox' ? e.target.checked : e.target.value });

  const handleSave = async () => {
    if (!form.name || !form.price) { toast.error('Name and price required'); return; }
    setSaving(true);
    try {
      const data = new FormData();
      Object.entries(form).forEach(([k, v]) => {
        if (k === 'flavors' || k === 'weights') data.append(k, JSON.stringify(v ? v.split(',').map(s => s.trim()).filter(Boolean) : []));
        else data.append(k, v);
      });
      if (imageFiles.length > 0) imageFiles.forEach(f => data.append('images', f));
      if (editId) await API.put(`/store/${editId}`, form);
      else await API.post('/store', data, { headers: { 'Content-Type': 'multipart/form-data' } });
      toast.success(editId ? 'Product updated!' : 'Product added!');
      setModal(false); setForm(emptyForm); setEditId(null); setImageFiles([]); load();
    } catch (err) { toast.error(err.response?.data?.message || 'Error'); }
    finally { setSaving(false); }
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Delete this product?')) return;
    try { await API.delete(`/store/${id}`); toast.success('Deleted'); load(); }
    catch { toast.error('Error'); }
  };

  const openEdit = (p) => {
    setForm({ ...p, flavors: p.flavors?.join(', ') || '', weights: p.weights?.join(', ') || '' });
    setEditId(p._id); setModal(true);
  };

  return (
    <AdminLayout title="Supplement Store Management">
      <div className="flex justify-end mb-6">
        <button onClick={() => { setModal(true); setEditId(null); setForm(emptyForm); }} className="btn-fire flex items-center gap-2 text-sm py-2.5 px-4">
          <Plus size={16} /> Add Product
        </button>
      </div>

      {loading ? (
        <div className="flex justify-center py-20"><div className="w-10 h-10 border-2 border-orange-500 border-t-transparent rounded-full animate-spin" /></div>
      ) : products.length === 0 ? (
        <div className="text-center py-20 text-gray-500">No products yet. Add your first product!</div>
      ) : (
        <div className="glass rounded-xl overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full text-sm">
              <thead className="border-b border-white/10">
                <tr className="text-gray-500 text-xs uppercase">
                  {['Product','Category','Price','Stock','Status','Actions'].map(h => (
                    <th key={h} className="text-left px-4 py-3 font-semibold">{h}</th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {products.map(p => (
                  <tr key={p._id} className="border-b border-white/5 hover:bg-white/2">
                    <td className="px-4 py-3 flex items-center gap-3">
                      {p.images?.[0] ? <img src={p.images[0]} alt={p.name} className="w-10 h-10 object-cover rounded-lg" /> :
                        <div className="w-10 h-10 bg-gray-800 rounded-lg flex items-center justify-center"><Package size={18} className="text-gray-600" /></div>}
                      <div>
                        <div className="text-white font-medium line-clamp-1">{p.name}</div>
                        <div className="text-gray-500 text-xs">{p.brand}</div>
                      </div>
                    </td>
                    <td className="px-4 py-3 text-gray-300 capitalize">{p.category}</td>
                    <td className="px-4 py-3">
                      <span className="text-white font-bold">₹{p.discountPrice || p.price}</span>
                      {p.discountPrice && <span className="text-gray-500 line-through text-xs ml-1">₹{p.price}</span>}
                    </td>
                    <td className="px-4 py-3">
                      <span className={`text-xs font-semibold ${p.stock > 0 ? 'text-green-400' : 'text-red-400'}`}>{p.stock}</span>
                    </td>
                    <td className="px-4 py-3">
                      <span className={`text-xs px-2 py-0.5 rounded-full ${p.isActive ? 'bg-green-500/20 text-green-400' : 'bg-red-500/20 text-red-400'}`}>
                        {p.isActive ? 'Active' : 'Inactive'}
                      </span>
                      {p.isFeatured && <span className="ml-1 text-xs bg-yellow-500/20 text-yellow-400 px-2 py-0.5 rounded-full">Featured</span>}
                    </td>
                    <td className="px-4 py-3">
                      <div className="flex gap-2">
                        <button onClick={() => openEdit(p)} className="p-1.5 text-orange-400 hover:bg-orange-400/10 rounded-lg"><Edit2 size={15} /></button>
                        <button onClick={() => handleDelete(p._id)} className="p-1.5 text-red-400 hover:bg-red-400/10 rounded-lg"><Trash2 size={15} /></button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {modal && (
        <div className="fixed inset-0 z-50 bg-black/60 backdrop-blur-sm flex items-center justify-center px-4">
          <motion.div initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }}
            className="bg-[#0d0d14] border border-white/10 rounded-2xl p-6 w-full max-w-2xl max-h-[90vh] overflow-y-auto">
            <div className="flex items-center justify-between mb-5">
              <h2 className="text-white font-bold text-xl">{editId ? 'Edit Product' : 'Add Product'}</h2>
              <button onClick={() => setModal(false)}><X size={20} className="text-gray-400" /></button>
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              {[
                { name: 'name', label: 'Product Name *', placeholder: 'Whey Protein 1kg' },
                { name: 'brand', label: 'Brand', placeholder: 'MuscleBlaze' },
                { name: 'price', label: 'MRP Price (₹) *', type: 'number', placeholder: '1999' },
                { name: 'discountPrice', label: 'Sale Price (₹)', type: 'number', placeholder: '1499' },
                { name: 'stock', label: 'Stock', type: 'number', placeholder: '50' },
                { name: 'flavors', label: 'Flavors (comma separated)', placeholder: 'Chocolate, Vanilla' },
                { name: 'weights', label: 'Sizes (comma separated)', placeholder: '1kg, 2kg, 4kg' },
              ].map(f => (
                <div key={f.name} className={f.name === 'name' ? 'sm:col-span-2' : ''}>
                  <label className="text-gray-400 text-xs block mb-1">{f.label}</label>
                  <input className="input-dark text-sm py-2" name={f.name} type={f.type || 'text'} value={form[f.name]} onChange={handleChange} placeholder={f.placeholder} />
                </div>
              ))}
              <div>
                <label className="text-gray-400 text-xs block mb-1">Category</label>
                <select className="input-dark text-sm py-2" name="category" value={form.category} onChange={handleChange}>
                  {CATEGORIES.map(c => <option key={c} value={c} className="bg-[#0d0d14] capitalize">{c}</option>)}
                </select>
              </div>
              <div className="flex gap-4 items-center">
                <label className="flex items-center gap-2 cursor-pointer">
                  <input type="checkbox" name="isFeatured" checked={form.isFeatured} onChange={handleChange} />
                  <span className="text-gray-300 text-sm">Featured</span>
                </label>
              </div>
              <div className="sm:col-span-2">
                <label className="text-gray-400 text-xs block mb-1">Description</label>
                <textarea className="input-dark text-sm min-h-[80px]" name="description" value={form.description} onChange={handleChange} />
              </div>
              {!editId && (
                <div className="sm:col-span-2">
                  <label className="text-gray-400 text-xs block mb-1">Product Images</label>
                  <input type="file" accept="image/*" multiple onChange={e => setImageFiles(Array.from(e.target.files))} className="text-gray-400 text-xs" />
                </div>
              )}
            </div>
            <div className="flex justify-end gap-3 mt-6">
              <button onClick={() => setModal(false)} className="px-4 py-2 text-gray-400 border border-white/10 rounded-lg text-sm">Cancel</button>
              <button onClick={handleSave} disabled={saving} className="btn-fire px-5 py-2 text-sm">
                {saving ? <span className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin inline-block" /> : (editId ? 'Update' : 'Add Product')}
              </button>
            </div>
          </motion.div>
        </div>
      )}
    </AdminLayout>
  );
}
